import{_ as a,o as t,c as r,ak as s}from"./chunks/framework.aEAtsvX-.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"大熊猫服务器文档v2","text":"教程、指南与规则","tagline":"服务器版本1.21.11 / 腐竹是萝莉控大蟑螂","actions":[{"theme":"brand","text":"⚡️【新手必看】安装和开始","link":"/install_and_start"},{"theme":"alt","text":"注意事项","link":"/notice"},{"theme":"alt","text":"插件与命令教程","link":"/plugins/"},{"theme":"alt","text":"进阶","link":"/advance/"},{"theme":"brand","text":"赞助服务器","link":"/index#赞助服务器"}]},"features":[{"title":"🐧QQ群号276051457","details":"愣着干嘛快进群"},{"title":"⭐本服性质：轻量插件生存服","details":"在不改变原版玩法和流程的情况下，加入了少许插件以增加娱乐性"},{"title":"⭐本服类型：商业服","details":"商业的部分是赞助，维持服务器开设需要钱，但是不会因任何的资助行为而造成玩家之间的差距"}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1776083463000}'),l={name:"index.md"};function i(n,e,o,d,c,h){return t(),r("div",null,[...e[0]||(e[0]=[s('<h2 id="欢迎" tabindex="-1">欢迎！ <a class="header-anchor" href="#欢迎" aria-label="Permalink to “欢迎！”">​</a></h2><p>我们是大熊猫服务器，一个<mark>高版本生存服</mark>！</p><p>我们追求原版体验，但是又引入了插件以提升娱乐性。</p><p>服务器适合养老，玩家氛围和谐，群友们很喜欢聊日常。</p><h2 id="为本文档做贡献" tabindex="-1">为本文档做贡献 <a class="header-anchor" href="#为本文档做贡献" aria-label="Permalink to “为本文档做贡献”">​</a></h2><ul><li>如果你想长期地进行本文档的编写，<a href="mailto:mechsteam@outlook.com" target="_blank" rel="noreferrer">联系作者</a>（或在q群联系<code>@再也不剪宣传片了</code>）吧！ <ul><li>如果你掌握这些技能，将有利于你对本文档的贡献工作！ <a href="https://skillicons.dev" target="_blank" rel="noreferrer"><img src="https://skillicons.dev/icons?i=git,github,md,vscode,vite,vue" alt="My Skills"></a></li></ul></li><li>如果你只想贡献一两篇文章，请<a href="https://github.com/Redersha/panda_server_guide_v2/issues" target="_blank" rel="noreferrer">提交issues</a>并附上md文件。</li></ul><h2 id="关于大熊猫服务器" tabindex="-1">关于大熊猫服务器 <a class="header-anchor" href="#关于大熊猫服务器" aria-label="Permalink to “关于大熊猫服务器”">​</a></h2><p>这是一个始于2019年9月的老牌服务器。自Minecraft 1.14版本开服，历经数个版本周期与周目，始终由服主一人独立管理、更新与维护，坚持运营至今。</p><h3 id="对于转型的考量" tabindex="-1">对于转型的考量 <a class="header-anchor" href="#对于转型的考量" aria-label="Permalink to “对于转型的考量”">​</a></h3><p>由于服务器运营需要承担电费、网费等基础开销，无法长期维持公益模式，自1.14版本后已全面转为商业服务器。我们坚持使用正版插件以确保稳定与安全，并注重售后维护。<strong>虽然转为商业运营，但游戏内充值玩家与非充值玩家之间的差距很小，不会因赞助而偏袒任何玩家，全力保障所有玩家的公平游戏体验。</strong></p><h3 id="对于未来" tabindex="-1">对于未来 <a class="header-anchor" href="#对于未来" aria-label="Permalink to “对于未来”">​</a></h3><p><strong>本服正朝轻RPG与多元化玩法发展，定位为插件服，而非纯粹的生电服。</strong> 在不完全禁止生电行为的前提下会进行适当限制，属于半生电服。通过拓展更多游戏内容，旨在延长服务器生命周期，为玩家提供持久而丰富的体验。</p><h2 id="赞助服务器" tabindex="-1">赞助服务器 <a class="header-anchor" href="#赞助服务器" aria-label="Permalink to “赞助服务器”">​</a></h2><p><strong>赞助是获得不影响游戏平衡的游戏权限的重要途径</strong>，主要包括三种方式：直接购买点券、购买月卡（减负包）以及参与众筹。</p><details class="details custom-block"><summary>点券</summary><p>点券是用于购买权限的主要代币，<strong>可兑换游戏币、装饰性或功能性的权限（如彩色聊天字体、更多附魔查询、称号装饰、增加上架物品数量等）</strong>，有效期通常为一个月。</p></details><details class="details custom-block"><summary>月卡</summary><p>月卡（减负包）为按月订阅服务，购买后可一次性获得200点券，并每日领取800游戏币和一个不死图腾；在有效期内，还能享受圈地价格降低0.1、领地上限+1，以及mcmmo经验获取增加10%的福利。</p></details><details class="details custom-block"><summary>众筹</summary><p>众筹则在服务器需要添加新插件时开放，<strong>由多名玩家共同赞助以筹集所需金额</strong>。参与众筹的玩家将加入众筹组，获得额外的领地及设家上限，并解锁部分娱乐和功能性插件权限（例如CMI的装饰性功能，如<code>/ride</code>、<code>/hat</code>、盔甲架编辑等），<strong>这些权限均以娱乐和便利为主，不会影响玩家间的游戏平衡。</strong></p></details><p>前两种可以在游戏中输入<code>/菜单</code>后，于界面右下角点击赞助菜单进入相关界面。</p>',18)])])}const _=a(l,[["render",i]]);export{p as __pageData,_ as default};
